import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/admin-dashboard.css';
import '../../styles/admin-layout.css';

export const AdminDashboard = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const response = await adminService.getAllUsers();
      setUsers(response.data.data || []);
    } catch (err) {
      setError('Lỗi tải danh sách người dùng');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="dashboard">
        <div className="flex-center admin-dashboard__loading-container">
          <div className="spinner"></div>
        </div>
      </div>
    );
  }
  const recentUsers = users.slice(0, 6);

  return (
    <div className="dashboard admin-page">

      {error && <div className="alert alert-error">{error}</div>}

      <div className="grid-2" style={{ alignItems: 'start' }}>
        <div className="card">
          <h3>Tổng người dùng</h3>
          <p className="stat-value" style={{ fontSize: '2rem', margin: '8px 0' }}>{users.length}</p>
          <div className="btn-group">
            <a className="btn btn-primary" href="/admin/users">Quản lý người dùng</a>
            <a className="btn btn-secondary" href="/admin/user-login-history">Lịch sử đăng nhập</a>
          </div>
        </div>

        <div className="card">
          <h3>Người dùng gần đây</h3>
          {recentUsers.length > 0 ? (
            <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
              {recentUsers.map((u) => (
                <li key={u.user_id} style={{ padding: '10px 0', borderBottom: '1px solid #eef2f7' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', gap: 12 }}>
                    <div>
                      <div style={{ fontWeight: 600 }}>{u.full_name || u.username}</div>
                      <div style={{ fontSize: '0.9rem', color: '#6b7280' }}>{u.email || '-'}</div>
                    </div>
                    <div style={{ textAlign: 'right' }}>
                      <div style={{ fontSize: '0.9rem' }}>{u.role_name || u.role || '-'}</div>
                      <div style={{ fontSize: '0.85rem', color: u.status ? '#16a34a' : '#dc2626' }}>{u.status ? 'Hoạt động' : 'Đã khóa'}</div>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          ) : (
            <p>Chưa có người dùng.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
